import React, { useEffect, useState } from 'react';
import axios from '../api/axiosConfig';

function ComplaintListPage({ user }) {
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!user) return;
    const fetchComplaints = async () => {
      setLoading(true);
      setError('');
      try {
        const response = await axios.get('/complaints');
        setComplaints(response.data);
      } catch (err) {
        setError('Unable to load complaints');
      } finally {
        setLoading(false);
      }
    };
    fetchComplaints();
  }, [user]);

  if (!user) {
    return <div className="card">Please login to see your complaint history.</div>;
  }

  return (
    <div className="card">
      <h2>Complaint History</h2>
      {loading && <div className="info-box">Loading complaints...</div>}
      {error && <div className="error-box">{error}</div>}
      {complaints.length === 0 && !loading && <p>You have not submitted any complaints yet.</p>}
      <div className="table-scroll">
        <table>
          <thead>
            <tr>
              <th>Title</th>
              <th>Category</th>
              <th>Status</th>
              <th>Date</th>
            </tr>
          </thead>
          <tbody>
            {complaints.map((item) => (
              <tr key={item._id}>
                <td>{item.title}</td>
                <td>{item.category}</td>
                <td>{item.status}</td>
                <td>{new Date(item.createdAt).toLocaleDateString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default ComplaintListPage;
